// Master Sheet → TEAM format mapping.
// Sheet баганы нэр монголоор; app дотор Latin field name ашиглана.
//
// Status logic:
//   - 'нээлттэй' (open position) → хасна
//   - 'идэвхтэй' / 'гарсан' / 'татгалзсан' / 'хүлээж буй' → бүгдийг буцаана
// Pending мөрүүдэд ID байхгүй байж болно — тэр үед Хүсэлтийн ID-г ID болгож ашиглана
// (CEO зөвшөөрөхдөө жинхэнэ M01/C07 г.м. ID assign хийнэ).
//
// Output: { team: [...] }

const rows = $input.all().map(it => it.json);

const BRANCH_MAP = {
  'Нэгдсэн': 'shared',
  'Удирдлага': 'shared',
  'M Event': 'm-event',
  'Camp':    'camp',
};

function mapBranch(label) {
  if (!label) return null;
  const trimmed = String(label).trim();
  return BRANCH_MAP[trimmed] || null;
}

function normalizeId(raw) {
  if (raw == null) return '';
  const s = String(raw).trim();
  if (/^\d{1,2}$/.test(s)) return s.padStart(3, '0');
  return s;
}

const team = [];
for (const r of rows) {
  if (!r) continue;
  const status = String(r['Төлөв'] || '').trim() || 'идэвхтэй';
  if (status === 'нээлттэй') continue;

  // ID — pending мөрд хоосон байж болно. Тэр үед Хүсэлтийн ID-г ашиглана.
  let id = normalizeId(r['ID']);
  const requestId = String(r['Хүсэлтийн ID'] || '').trim();
  if (!id && requestId) id = requestId;
  if (!id) continue;

  const primary = mapBranch(r['Бүлэг']);
  const secondary = mapBranch(r['Хавсарсан бүлэг']);
  const branches = [];
  if (primary) branches.push(primary);
  if (secondary && secondary !== primary) branches.push(secondary);

  const role = String(r['Албан тушаал'] || '').trim();

  if (id === 'CEO') {
    if (!branches.includes('m-event')) branches.push('m-event');
    if (!branches.includes('camp')) branches.push('camp');
    if (!branches.includes('shared')) branches.push('shared');
  }

  team.push({
    id,
    name: String(r['Овог нэр'] || '').trim(),
    role,
    level: parseInt(r['Зэрэглэл'] || '40', 10) || 40,
    pin: String(r['PIN'] || '').trim(),
    phone: String(r['Утас'] || '').trim(),
    email: String(r['И-мэйл'] || '').trim(),
    branches,
    group: String(r['Бүлэг'] || '').trim(),
    status,
    request_id: requestId || null,
    rd: String(r['РД'] || '').trim() || null,
    address: String(r['Гэрийн хаяг'] || '').trim() || null,
    photo: String(r['Зургийн URL'] || '').trim() || null,
    emergency_name: String(r['Яаралтай үед холбоо барих хүн'] || '').trim() || null,
    emergency_phone: String(r['Утас 2'] || '').trim() || null,
    left_at: String(r['Гарсан огноо'] || '').trim() || null,
    joined_at: String(r['Орсон огноо'] || '').trim() || null,
    requested_at: String(r['Хүсэлт өгсөн'] || '').trim() || null,
    seasonal_from: String(r['Улирлын эхлэл'] || '').trim() || null,
    seasonal_to:   String(r['Улирлын төгсгөл'] || '').trim() || null,
  });
}

return [{ json: { team, count: team.length, generated_at: new Date().toISOString() } }];
